const bcrypt = require('bcrypt');

router.post('/fixed/register', async (req, res) => {
  const { username, password } = req.body;
  // ✅ cost=12 means ~250ms per hash — slow enough to deter brute force
  const hash = await bcrypt.hash(password, 12);
  db.prepare(
    'INSERT INTO users (username, password_bcrypt) VALUES (?, ?)'
  ).run(username, hash);
  res.json({ algorithm: 'bcrypt (cost 12)', note: 'Hash not returned to client' });
});
